package counter

import "sync"

type Counter struct {
	mu     sync.RWMutex
	values map[string]int64
}

func New() *Counter {
	return &Counter{values: make(map[string]int64)}
}

func (c *Counter) Increment(key string) int64 {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.values[key]++
	return c.values[key]
}

func (c *Counter) Get(key string) int64 {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.values[key]
}
